# Column Definitions

Columns are defined with ColumnDef objects in a useMemo array.

```tsx
const columns = React.useMemo<ColumnDef<Person, any>[]>(
  () => [
    {
      accessorKey: 'firstName',
      cell: (info) => info.getValue(),
    },
    {
      accessorFn: (row) => row.lastName,
      id: 'lastName',
      cell: (info) => info.getValue(),
      header: () => <span>Last Name</span>,
    },
    {
      accessorFn: (row) => `${row.firstName} ${row.lastName}`,
      id: 'fullName',
      header: 'Full Name',
      cell: (info) => info.getValue(),
    },
    {
      accessorKey: 'age',
      header: () => 'Age',
      meta: { filterVariant: 'range' },
    },
    {
      accessorKey: 'status',
      header: 'Status',
      meta: { filterVariant: 'select' },
    },
  ],
  []
);
```

Key props: accessorKey, accessorFn, id, cell, header, footer, meta, filterFn, sortingFn, enableSorting, enableColumnFilter.

**Category:** Core
**URL:** https://tanstack.com/table/latest/docs/guide/column-defs

# Rendering with flexRender

Use flexRender to render table headers and cells.

```tsx
<table>
  <thead>
    {table.getHeaderGroups().map((headerGroup) => (
      <tr key={headerGroup.id}>
        {headerGroup.headers.map((header) => (
          <th key={header.id} colSpan={header.colSpan}>
            {header.isPlaceholder ? null : (
              <div
                className={header.column.getCanSort() ? 'cursor-pointer select-none' : ''}
                onClick={header.column.getToggleSortingHandler()}
              >
                {flexRender(header.column.columnDef.header, header.getContext())}
                {{asc: ' 🔼', desc: ' 🔽'}[header.column.getIsSorted() as string] ?? null}
              </div>
            )}
          </th>
        ))}
      </tr>
    ))}
  </thead>
  <tbody>
    {table.getRowModel().rows.map((row) => (
      <tr key={row.id}>
        {row.getVisibleCells().map((cell) => (
          <td key={cell.id}>
            {flexRender(cell.column.columnDef.cell, cell.getContext())}
          </td>
        ))}
      </tr>
    ))}
  </tbody>
</table>
```

Key methods: table.getHeaderGroups(), table.getRowModel(), header.getContext(), cell.getContext(), header.column.getCanSort(), header.column.getToggleSortingHandler().

**Category:** Rendering
**URL:** https://tanstack.com/table/latest/docs/guide/tables

# Column Meta for Filter Variants

Extend ColumnMeta with TypeScript module augmentation.

```tsx
declare module '@tanstack/react-table' {
  interface ColumnMeta<TData extends RowData, TValue> {
    filterVariant?: 'text' | 'range' | 'select'
  }
}
```

Then use in column definitions:
```tsx
{
  accessorKey: 'age',
  header: () => 'Age',
  meta: { filterVariant: 'range' },
},
{
  accessorKey: 'status',
  header: 'Status',
  meta: { filterVariant: 'select' },
}
```

Access in Filter component:
```tsx
function Filter({ column }: { column: Column<any, unknown> }) {
  const { filterVariant } = column.columnDef.meta ?? {};
  if (filterVariant === 'range') return <RangeFilter />;
  if (filterVariant === 'select') return <SelectFilter />;
  return <TextFilter />;
}
```

**Category:** TypeScript
**URL:** https://tanstack.com/table/latest/docs/guide/column-defs

# Column Grouping and Aggregation

```typescript
import {getGroupedRowModel, getExpandedRowModel} from '@tanstack/react-table';
const columns: ColumnDef<Person>[] = [{
  header: 'Name',
  columns: [{
    accessorKey: 'firstName',
    getGroupingValue: (row) => `${row.firstName} ${row.lastName}`,
  }, {
    accessorFn: (row) => row.lastName,
    id: 'lastName'
  }],
}, {
  header: 'Info',
  columns: [{
    accessorKey: 'age',
    aggregationFn: 'median'
  }, {
    accessorKey: 'visits',
    aggregationFn: 'sum'
  }, {
    accessorKey: 'progress',
    aggregationFn: 'mean',
    aggregatedCell: ({getValue}) => Math.round(getValue<number>() * 100) / 100 + '%'
  }],
}];
const table = useReactTable({getGroupedRowModel: getGroupedRowModel(), getExpandedRowModel: getExpandedRowModel()});
```

Built-in aggregation functions: sum, count, min, max, extent, mean, median, unique, uniqueCount.

# Row Selection

```typescript
const columns: ColumnDef<Person>[] = [{
  id: 'select',
  header: ({table}) => <IndeterminateCheckbox checked={table.getIsAllRowsSelected()} indeterminate={table.getIsSomeRowsSelected()} onChange={table.getToggleAllRowsSelectedHandler()} />,
  cell: ({row}) => <IndeterminateCheckbox checked={row.getIsSelected()} disabled={!row.getCanSelect()} onChange={row.getToggleSelectedHandler()} />,
}];
const [rowSelection, setRowSelection] = useState({});
const table = useReactTable({state: {rowSelection}, enableRowSelection: true, onRowSelectionChange: setRowSelection});
```

# Column Pinning

```typescript
const getCommonPinningStyles = (column) => {
  const isPinned = column.getIsPinned();
  return {position: isPinned ? 'sticky' : 'relative', left: isPinned === 'left' ? `${column.getStart('left')}px` : undefined, right: isPinned === 'right' ? `${column.getAfter('right')}px` : undefined, zIndex: isPinned ? 1 : 0, backgroundColor: 'white'};
};
// Pin controls
<button onClick={() => header.column.pin('left')}>Pin Left</button>
<button onClick={() => header.column.pin('right')}>Pin Right</button>
<button onClick={() => header.column.pin(false)}>Unpin</button>
```

# Column Visibility and Ordering

```tsx
// Toggle all columns visibility
<input type="checkbox" checked={table.getIsAllColumnsVisible()} onChange={table.getToggleAllColumnsVisibilityHandler()} />
// Toggle individual column
{table.getAllLeafColumns().map(column => (
  <label key={column.id}>
    <input type="checkbox" checked={column.getIsVisible()} onChange={column.getToggleVisibilityHandler()} /> {column.id}
  </label>
))}
// Randomize column order
table.setColumnOrder(faker.helpers.shuffle(table.getAllLeafColumns().map(d => d.id)));
```

# Virtualized Infinite Scrolling

```typescript
import {useReactTable, getCoreRowModel, getSortedRowModel} from '@tanstack/react-table';
import {useInfiniteQuery, keepPreviousData} from '@tanstack/react-query';
import {useVirtualizer} from '@tanstack/react-virtual';
const fetchSize = 50;
const {data, fetchNextPage, isFetching} = useInfiniteQuery({queryKey: ['people', sorting], queryFn: async ({pageParam = 0}) => fetchData(pageParam * fetchSize, fetchSize, sorting), initialPageParam: 0, getNextPageParam: (_last, groups) => groups.length, placeholderData: keepPreviousData});
const rowVirtualizer = useVirtualizer({count: rows.length, estimateSize: () => 33, getScrollElement: () => tableContainerRef.current});
// Auto-fetch on scroll
const fetchMoreOnBottomReached = (el) => {
  if (el && el.scrollHeight - el.scrollTop - el.clientHeight < 500 && !isFetching && totalFetched < totalDBRowCount) fetchNextPage();
};
```
